219	// Sends one P packet whose body is built by the supplied encoder. A
220	// missing register name is silently skipped: not every QEMU build
221	// advertises every PMP slot or extension CSR, so absence isn't fatal.
222	template<class Session, class Encoder>
223	inline void try_write_named(Session& sess,
224	                            const gdbstub::RegMap& map,
225	                            const std::string& name,
226	                            Encoder&& encoder)
227	{
228	  const auto reg_num = map.find(name);
229	  if (!reg_num) return;
230	  auto reply = sess.send_command(encoder(*reg_num));
231	  if (reply != "OK")
232	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
233	                             + reply);
234	}
