236	template<class Session>
237	inline void try_write_named_u64(Session& sess,
238	                                const gdbstub::RegMap& map,
239	                                const std::string& name,
240	                                uint64_t value)
241	{
242	  try_write_named(sess, map, name, [&](unsigned r) {
243	    return gdbstub::encode_p_body(r, value);
244	  });
245	}
