262	inline constexpr std::array<std::pair<const char*, uint64_t hybrid_state_v1::*>,
263	                            13>
264	  kCsrByName = {{
265	    {"mstatus",  &hybrid_state_v1::mstatus},
266	    {"mepc",     &hybrid_state_v1::mepc},
267	    {"mtvec",    &hybrid_state_v1::mtvec},
268	    {"mcause",   &hybrid_state_v1::mcause},
