270	    {"mscratch", &hybrid_state_v1::mscratch},
271	    {"medeleg",  &hybrid_state_v1::medeleg},
272	    {"mideleg",  &hybrid_state_v1::mideleg},
273	    {"mip",      &hybrid_state_v1::mip},
274	    {"mie",      &hybrid_state_v1::mie},
275	    {"mcycle",   &hybrid_state_v1::mcycle},
