80	private:
81	  auto read_64bit_register(uint16_t regno) -> uint64_t
82	  {
83	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
84	                                                     /*write=*/false));
85	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
