88	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
89	    // Clear the error and report 0 for that field so the next read can
90	    // proceed - a missing CSR mirrors as zero rather than corrupting the
91	    // adjacent slot.
92	    const auto status = bus_.read(RD::kAbstractcs);
